const input = $input.first().json;
const body = input.body || input;

const service_id = String(body.service_id || 'google_calendar');
const success = body.success;
const result = success ? 'success' : 'failure';
const error_message = body.error_message || null;

const SERVICE_ID_RE = /^[a-zA-Z0-9_-]{1,100}$/;
if (!SERVICE_ID_RE.test(service_id)) {
  return [{
    json: {
      success: false,
      error_code: 'INVALID_SERVICE_ID',
      error_message: 'Invalid service_id',
      data: null,
      _meta: { source: 'CB_02_Record_Result', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
      _exit_early: true
    }
  }];
}

const safe_error = error_message
  ? String(error_message).substring(0, 500).replace(/'/g, "''")
  : 'none';

return [{ json: { service_id, service_id_sanitized: service_id.replace(/'/g, "''"), result, error_message: safe_error, metadata: body.metadata || {} } }];

const items = $input.all();
const upstream = $('Build Query').first()?.json || {};

if (!items.length || !items[0].json || !items[0].json.service_id) {
  // Check if there was an error in Postgres
  const error = items[0]?.json?.error || items[0]?.json?.message;
  if (error) {
    return [{ json: {
      success: false,
      error_code: 'DB_ERROR',
      error_message: error,
      data: null,
      _meta: { source: 'CB_02_Record_Result', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
      _route: 'done'
    }}];
  }

  return [{ json: {
    success: false,
    error_code: 'SERVICE_NOT_FOUND',
    error_message: 'Service not initialized in circuit_breaker_state table',
    data: null,
    _meta: { source: 'CB_02_Record_Result', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _route: 'done'
  }}];
}

const state = items[0].json;
return [{ json: {
  success: true,
  error_code: null,
  error_message: null,
  data: {
    recorded: true,
    service_id: state.service_id,
    new_state: state.state,
    failure_count: state.failure_count,
    success_count: state.success_count
  },
  _meta: { source: 'CB_02_Record_Result', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
  _route: 'done'
}}];

const input = $input.first().json;
if (input._exit_early) return [];
return [{ json: input }];

const input = $input.first().json;
if (!input._exit_early) return [];
return [{ json: input }];

const items = $input.all();
let finalItem = items.find(i => i.json.data !== undefined || i.json.error_code !== undefined);

if (!finalItem) {
  return [{ json: {
    success: false,
    error_code: 'PIPELINE_ERROR',
    error_message: 'No valid output found',
    data: null,
    _meta: { source: 'CB_02_Record_Result', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
  }}];
}

return [{ json: finalItem.json }];
